import{_ as t,c as o,o as a,a5 as i,fk as r,fl as s,fm as n}from"./chunks/framework.Cak6VIuI.js";const g=JSON.parse('{"title":"Liii STEM Basics","description":"","frontmatter":{"title":"Liii STEM Basics"},"headers":[],"relativePath":"docs/guide-quick-start.md","filePath":"docs/guide-quick-start.md","lastUpdated":1773646151000}'),d={name:"docs/guide-quick-start.md"};function c(l,e,m,u,h,p){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="liii-stem-basics" tabindex="-1">Liii STEM Basics <a class="header-anchor" href="#liii-stem-basics" aria-label="Permalink to “Liii STEM Basics”">​</a></h1><p>When you first use Liii STEM, you only need to understand two ideas: <strong>modes</strong> and <strong>environments</strong>. They affect what appears in the toolbar and how your content is formatted.</p><p><img src="'+r+'" alt="Toolbars"></p><blockquote><p>Liii STEM has five main UI areas: tab bar, menu bar, mode toolbar, focus (current environment) toolbar, and status bar.</p></blockquote><h2 id="modes" tabindex="-1">Modes <a class="header-anchor" href="#modes" aria-label="Permalink to “Modes”">​</a></h2><p>A mode decides what you are currently editing. Liii STEM commonly uses three modes:</p><ul><li><strong>Text mode</strong>: the default mode for body text, titles, images, and tables</li><li><strong>Math mode</strong>: press <code>$</code> or <code>Alt</code> + <code>$</code> to enter it for formula editing</li><li><strong>Command mode</strong>: press <code>\\</code> to enter LaTeX-style commands or macros</li></ul><p>The easiest rule to remember is: <strong>use Text mode for normal writing, and switch to Math mode for formulas.</strong></p><p><img src="'+s+'" alt="Three modes"></p><blockquote><p>The mode toolbar changes when you switch modes.</p></blockquote><h2 id="environments" tabindex="-1">Environments <a class="header-anchor" href="#environments" aria-label="Permalink to “Environments”">​</a></h2><p>Titles, sections, formulas, highlights, enunciation blocks, and tables can all be treated as environments.</p><p>The environment where your cursor is placed is the current <strong>focus</strong>. When the focus changes, the focus toolbar changes with it, and you can use that toolbar to adjust properties of the current environment.</p><p><img src="'+n+'" alt="Focus toolbar"></p><blockquote><p>To keep the content and leave the current environment, press <code>Ctrl</code> + <code>Backspace</code>.</p></blockquote><h2 id="further-reading" tabindex="-1">Further Reading <a class="header-anchor" href="#further-reading" aria-label="Permalink to “Further Reading”">​</a></h2><p>If you already understand modes and environments, continue with:</p><ul><li><a href="./guide-magic-paste.html">Magic Paste Guide</a></li><li><a href="./guide-number-sections.html">Sections and Table of Contents</a></li><li><a href="./guide-enunciation.html">Enunciation Guide</a></li></ul>',18)])])}const b=t(d,[["render",c]]);export{g as __pageData,b as default};
